// Access the input data
const inputText = $json["output"];

// Replace \n or \\n with real new lines, and clean up extra slashes
const formattedText = inputText
    .replace(/\\n/g, "\n")          // Converts literal '\n' to actual newlines
    .replace(/\n{2,}/g, "\n\n")     // Ensures double newlines for paragraph breaks
    .replace(/\\"/g, '"')           // Fixes escaped quotes
    .replace(/\\'/g, "'");          // Fixes escaped single quotes

// Return the formatted text as a new field
return [
  {
    json: {
      formattedOutput: formattedText
    }
  }
];

